    pub fn baracuda_kernels_contiguize_b1_run(
        dest: *mut c_void,
        source: *const c_void,
        shape: *const i32,
        source_strides: *const i64,
        source_offset: i64,
        rank: i32,
        stream: *mut c_void,
    ) -> i32;

    /// Contiguize, 2-byte element (f16, bf16).
    pub fn baracuda_kernels_contiguize_b2_run(
        dest: *mut c_void,
        source: *const c_void,
        shape: *const i32,
        source_strides: *const i64,
        source_offset: i64,
        rank: i32,
        stream: *mut c_void,
    ) -> i32;

    /// Contiguize, 4-byte element (f32, F32Strict, i32).
    pub fn baracuda_kernels_contiguize_b4_run(
        dest: *mut c_void,
        source: *const c_void,
        shape: *const i32,
        source_strides: *const i64,
        source_offset: i64,
        rank: i32,
        stream: *mut c_void,
    ) -> i32;

    /// Contiguize, 8-byte element (f64, i64, Complex32).
    pub fn baracuda_kernels_contiguize_b8_run(
        dest: *mut c_void,
        source: *const c_void,
        shape: *const i32,
        source_strides: *const i64,
        source_offset: i64,
        rank: i32,
        stream: *mut c_void,
    ) -> i32;

    /// Contiguize, 16-byte element (Complex64).
    pub fn baracuda_kernels_contiguize_b16_run(
        dest: *mut c_void,
        source: *const c_void,
        shape: *const i32,
        source_strides: *const i64,
        source_offset: i64,
        rank: i32,
        stream: *mut c_void,
    ) -> i32;

    /// Contiguize, nibble-packed (S4 / U4). Returns status 3
