    pub fn baracuda_kernels_where_backward_bf16_run(
        numel: i64,
        cond: *const c_void,
        dy: *const c_void,
        da: *mut c_void,
        db: *mut c_void,
        workspace: *mut c_void,
        workspace_bytes: usize,
        stream: *mut c_void,
    ) -> i32;

    /// `where` backward, f64.
