    // Outputs (modified in place):
    //   k_cache        : T[B, H, L_max, D_k]
    //   v_cache        : T[B, H, L_max, D_v]
    // Cells where `cache_offsets[b] + l_new >= L_max` are silently skipped.
    // =========================================================================

